class Solution {
public:
    int clumsy(int n) {
        if (n == 1) return 1;
        long long res = n;
        for (int i = n - 1; i > 1; --i) {
            if (i % 4 == 1) {
                res *= i;
            } else if (i % 4 == 2) {
                res /= i;
            } else if (i % 4 == 3) {
                res += i;
            } else {
                res -= i;
            }
        }
        return (int)res;
    }
};
